files.content:
body {
  background-color: rosybrown;
  font-family: Arial, sans-serif;
}

.business-card {
  background-color: lavenderblush;
  border: 3px solid darkslategray;
  padding: 20px;
  text-align: center;
  font-size: 16px;
  width: 300px;
  margin-left: auto;
  margin-right: auto;
  margin-top: 100px;
}

.profile-image {
  max-width: 100%;
  width: 150px;
  height: 150px;
  margin-bottom: 10px;
  border: 2px solid lightgray;
}

.full-name {
  font-size: 24px;
  color: darkslategray;
}

.designation {
  font-size: 18px;
  color: gray;
}

.company {
  font-size: 16px;
  color: darkgray;
}

p {
  margin: 5px 0;
}

a {
  text-decoration: none;
}

.social-media {
  margin-top: 10px;
  font-size: 14px;
}

.social-media a {
  margin: 10px;
  color: maroon;
}

hr {
  margin: 20px 0;
}
